// Simplified commit-reveal pattern to resist front-running
mapping(address => bytes32) public commitments;

function commit(bytes32 hash) external {
    commitments[msg.sender] = hash;
}

function reveal(uint256 value, uint256 nonce) external {
    require(
        keccak256(abi.encodePacked(value, nonce)) == commitments[msg.sender],
        "Hash mismatch"
    );
    // proceed knowing the value wasn't visible in the mempool beforehand
}

